var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"천천히… 숨을 들이마십니다.","JPN":"ゆっくりと……息を吸ってください。","ENG":"Now... slowly inhale.","TWN":"慢慢地……吸氣。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"침묵은 곧 고요요. 마음을 가라앉힘에 비로소 우리는 평온을 되찾을 것입니다.","JPN":"沈黙は静寂。心を落ち着かせると私たちは平穏を取り戻せるのです。","ENG":"Silence is serene, and only by calming our minds can we regain peace.","TWN":"沉默即是寧靜。只有心平氣和，我們才能重獲平靜。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"몸에 힘을 빼고… 웃으며 세 번 말합니다.","JPN":"体から力を抜いて……ほほ笑みながら3回唱えます。","ENG":"Relax all the tension in your body... and chant with me three times with a smile.","TWN":"放鬆身體……微笑著說三遍。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"나는 행복하다!","JPN":"私は幸せだ！","ENG":"I'm happy!","TWN":"我很幸福！"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":" 나는 행복하다!","JPN":" 私は幸せだ！","ENG":" I'm happy!","TWN":"我很幸福！"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":" 나는 행복하다!","JPN":" 私は幸せだ！","ENG":" I'm happy!","TWN":"我很幸福！"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"시끄러워, 여기 너만 있냐?","JPN":"うるせえよ、ここにいるのはお前だけじゃねえぞ。","ENG":"Shut up. You think you own this place, huh?!","TWN":"閉嘴，這裡只有你嗎？"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"행복하긴 개뿔. 하다못해 그 확성기 좀 끄란 말이야!","JPN":"幸せなはずねえだろ。いいかげんその拡声器はやめろよ！","ENG":"Happy, my foot. At least turn that stupid megaphone off!","TWN":"幸福個鬼，給我把把那個擴音器關掉！"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"나는 행복하다. 나는 행복하다. 나는……","JPN":"私は幸せだ。私は幸せだ。私は……","ENG":"I'm happy. I'm happy. I'm...","TWN":"我很幸福。我很幸福。我很……"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"subtitle","speaker":null,"text":{"KOREA":"그라운드 원. 카운터 범죄 수용소.\\n<color=#ffd34c>G1 보안교육대</color>.","JPN":"グラウンド・ワン。カウンター犯罪者収容所。\\n<color=#ffd34c>G1保安教育隊</color>。","ENG":"[[","TWN":"G1，制裁者罪犯收容所\\n<color=#ffd34c>安全教育中心</color>.","SCN":"G1，制裁者罪犯收容所\\n<color=#ffd34c>安全教育中心</color>，"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"subtitle","speaker":null,"text":{"KOREA":"수감번호 24601. <color=#ffd34c>유피</color>.","JPN":"収容番号24601。<color=#ffd34c>ユピ</color>。","ENG":"Inmate No. 24601. <color=#ffd34c>Yuppie</color>.","TWN":"囚犯編號24601，<color=#ffd34c>悠菲</color>。","SCN":"囚犯编号24601，<color=#ffd34c>尤菲</color>。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"불행해…….","JPN":"不幸だよ……","ENG":"I'm so miserable...","TWN":"不幸……"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"심금을 울리는 목소리. 마드모아젤.","JPN":"心の琴線に触れる声。マドモアゼル。","ENG":"Your voice plucks my heartstrings, mademoiselle.","TWN":"真是動人心弦的聲音，小姐。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"죄를 뉘우치고자 하는 마음. 이 로저는 실로 존경스럽군요.","JPN":"罪を悔もうとするその心。このロジャーは大変尊敬しています。","ENG":"Your desire to repent for your sins. I, Roger, am truly impressed.","TWN":"你的懺悔之心，連我羅杰也感到敬佩。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"subtitle","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"수감번호 24600. <color=#ffd34c>로저</color>.","JPN":"収容番号24600。<color=#ffd34c>ロジャー</color>。","ENG":"Inmate No. 24600. <color=#ffd34c>Roger</color>.","TWN":"囚犯編號24600，<color=#ffd34c>羅杰</color>。","SCN":"囚犯编号24600，<color=#ffd34c>罗杰</color>。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"필시 그 확성기는 회개를 위한 목어일 터.","JPN":"その拡声器はきっと懺悔のための木魚であるはず。","ENG":"That megaphone must be a wooden fish used in Buddhism for repentance.","TWN":"那個擴音器必定是為了懺悔而用的木魚吧。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"어… 아뇨? 그냥 성인마냥 주절대면 조금 해탈할 수 있지 않을까 싶었는데요.","JPN":"えっ……違います。聖人のようにそれっぽく呟いてれば、ちょっとは解脱できるんじゃないかと思って。","ENG":"Uh... No? I just thought that I'd feel a little liberated if I rambled on like a saint.","TWN":"呃……不是呀？我只是覺得像聖人一樣嘮叨幾句，或許能有點解脫感……"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"마음에 확 와닿게 한달까. 제 카운터 능력이랑 연관 있거든요.","JPN":"それにこれが心にぐっとくるというか。私のカウンター能力と関係があるんですよね。","ENG":"I think I can reach enlightenment, or something. It's related to my Counter ability.","TWN":"說不定能有共鳴呢……這和我的制裁者能力有點關係。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"뭐, 감옥에 갇힌 시점에서 이제 와 무슨 소용이겠냐만.","JPN":"まあ、牢獄に閉じ込められてる時点で、今は何の役にも立ちませんけど。","ENG":"But what good is it now that I'm in prison?","TWN":"唉，都已經被關進監獄了，現在說什麼也沒用了。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"하루 아침에 범죄자가 되다니. 역시 사람 일은 모르고 볼 일이네요.","JPN":"まさか一朝一夕に犯罪者になるなんて。やっぱり人生ってわからないですね。","ENG":"Becoming a criminal overnight. Life really is full of surprises.","TWN":"一夜之間成了罪犯。果然世事難料啊。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"세상은 부조리함으로 가득합니다, 마드모아젤.","JPN":"世界は不条理に満ちています、マドモアゼル。","ENG":"The world is full of absurdity, mademoiselle.","TWN":"沒錯。這個世界充滿了不公，小姐。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"저만 하더라도 아이가 떨어진 사탕을 주워 먹는 걸 말렸다는 이유로 이곳에 왔지요.","JPN":"僕もまた、子どもが落とした飴を拾って食べようとするところを止めたという理由でここに来ました。","ENG":"Look at me. I was sent here because I stopped a kid from eating candy off the floor.","TWN":"我只不過是為了阻止孩子吃掉在地上的糖果，就被送到了這裡。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그럴 수가 있나요?","JPN":"そんなことでですか？","ENG":"Can they even do that?","TWN":"怎麼會這樣呢……？"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"제 얼굴을 본 아이가 울음을 터트렸습니다.","JPN":"僕の顔を見た子どもが泣き始めました。","ENG":"Well, the child burst into tears after seeing my face.","TWN":"那個孩子一看到我的臉就哭了。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"아이의 사탕을 뺏은 것처럼 보이는 거구… 남들이 보기엔 전 쓰레기였겠지요.","JPN":"子どもの飴を奪ったように見える巨漢……他人から見た僕はクズ同然だったのでしょう。","ENG":"It must have looked like a man was trying to steal candy from a baby... So to others, I must have looked like a piece of trash.","TWN":"不知道的人還以為是我搶了他的糖果……果然在別人眼裡，我就是個垃圾吧……"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이런 젠장!","JPN":"そんな！","ENG":"Dang it!","TWN":"太不公平了！"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};